class Solution:
    def numberOfArrays(self, s: str, k: int) -> int:
        MOD = 10**9 + 7
        n = len(s)
        k_len = len(str(k))
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            for j in range(max(0, i - k_len), i):
                seg = s[j:i]
                if seg[0] == '0':
                    continue
                val = int(seg)
                if 1 <= val <= k:
                    dp[i] = (dp[i] + dp[j]) % MOD
        return dp[n]

