var numberOfArrays = function(s, k) {
    const MOD = 1000000007n;
    const n = s.length;
    const kStr = String(k);
    const kLen = kStr.length;
    const dp = new Array(n + 1).fill(0n);
    dp[0] = 1n;
    for (let i = 1; i <= n; i++) {
        for (let j = Math.max(0, i - kLen); j < i; j++) {
            const seg = s.slice(j, i);
            if (seg[0] === '0') continue;
            if (seg.length < kLen || (seg.length === kLen && seg <= kStr)) {
                dp[i] = (dp[i] + dp[j]) % MOD;
            }
        }
    }
    return Number(dp[n]);
};
